INSERT INTO public.exam_questions (question, correct_answer, wrong_answers, all_answers, explanation, explain_on, question_type, subtopic, tier, calculator, difficulty, marks, estimated_time_sec, image_url, image_alt)
VALUES ('Solve the simultaneous equations:

  \begin{aligned} 2x + y &= 13 \\ 6x + y &= 21 \end{aligned}', 'x = 2, y = 9', ARRAY['x = 9, y = 2', 'x = 3, y = 9', 'x = 2, y = 10'], ARRAY['x = 2, y = 10', 'x = 9, y = 2', 'x = 3, y = 9', 'x = 2, y = 9'], 'Step 1: Subtract the first equation from the second to eliminate y.

Step 2: (6x + y) - (2x + y) = 21 - 13

Step 3: 4x = 8 so x = 2 = 2.

Step 4: Substitute x = 2 into 2x + y = 13: 2(2) + y = 13 so y = 9 = 9.

Final answer: x = 2, y = 9', 'always', 'Algebra', 'algebra|simultaneous', 'Foundation Tier', 'Calculator', 3, 4, 240, NULL, NULL);

INSERT INTO public.exam_questions (question, correct_answer, wrong_answers, all_answers, explanation, explain_on, question_type, subtopic, tier, calculator, difficulty, marks, estimated_time_sec, image_url, image_alt)
VALUES ('Solve the simultaneous equations:

  \begin{aligned} 2x + y &= 15 \\ 3x + y &= 21 \end{aligned}', 'x = 6, y = 3', ARRAY['x = 3, y = 6', 'x = 7, y = 3', 'x = 6, y = 4'], ARRAY['x = 6, y = 4', 'x = 7, y = 3', 'x = 3, y = 6', 'x = 6, y = 3'], 'Step 1: Subtract the first equation from the second to eliminate y.

