INSERT INTO public.exam_questions (question, correct_answer, wrong_answers, all_answers, explanation, explain_on, question_type, subtopic, tier, calculator, difficulty, marks, estimated_time_sec, image_url, image_alt)
VALUES ('Solve x^2 - 5x + 4 = 0.', 'x = -4 or x = -1', ARRAY['x = 4 or x = 1', 'x = -5', 'x = -4 only'], ARRAY['x = -4 or x = -1', 'x = 4 or x = 1', 'x = -4 only', 'x = -5'], 'Step 1: Factorise: x^2 - 5x + 4 = (x + 4)(x + 1).

Step 2: Set each bracket to 0:

x + 4 = 0 gives x = -4

x + 1 = 0 gives x = -1

Final answer: x = -4 or x = -1', 'always', 'Algebra', 'algebra|quadratics', 'Foundation Tier', 'Calculator', 4, 3, 220, NULL, NULL);

INSERT INTO public.exam_questions (question, correct_answer, wrong_answers, all_answers, explanation, explain_on, question_type, subtopic, tier, calculator, difficulty, marks, estimated_time_sec, image_url, image_alt)
VALUES ('Solve x^2 - 1x - 20 = 0.', 'x = -5 or x = 4', ARRAY['x = 5 or x = -4', 'x = -1', 'x = -5 only'], ARRAY['x = 5 or x = -4', 'x = -5 or x = 4', 'x = -1', 'x = -5 only'], 'Step 1: Factorise: x^2 - 1x - 20 = (x + 5)(x - 4).

