VALUES ('Solve x^2 - 2x - 8 = 0.', 'x = 2 or x = -4', ARRAY['x = -2 or x = 4', 'x = -2', 'x = 2 only'], ARRAY['x = -2', 'x = -2 or x = 4', 'x = 2 only', 'x = 2 or x = -4'], 'Step 1: Factorise: x^2 - 2x - 8 = (x - 2)(x + 4).

